export async function seedBoycottxAdditives(db: PostgresJsDatabase): Promise<number> {
  let count = 0;

  // Phase 1: Insert new additives (ON CONFLICT → update names + veg flags)
  if (BOYCOTTX_NEW.length > 0) {
    // Batch insert in chunks of 50 to stay within PG parameter limits
    const BATCH_SIZE = 50;
    for (let i = 0; i < BOYCOTTX_NEW.length; i += BATCH_SIZE) {
      const batch = BOYCOTTX_NEW.slice(i, i + BATCH_SIZE);
      await db
        .insert(additives)
        .values(batch)
        .onConflictDoUpdate({
          target: additives.code,
          set: {
            // Don't overwrite our rich Naqiy data — only fill gaps
            isVegetarian: sql`COALESCE(additives.is_vegetarian, excluded.is_vegetarian)`,
            isVegan: sql`COALESCE(additives.is_vegan, excluded.is_vegan)`,
            dataSource: sql`CASE WHEN additives.data_source = 'naqiy' THEN 'naqiy' ELSE excluded.data_source END`,
          },
        });
      count += batch.length;
    }
  }

  // Phase 2: Enrich existing entries with veg/vegan flags
  const enrichCodes = Object.keys(ENRICHMENT_MAP);
  for (const code of enrichCodes) {
    const { isVegetarian, isVegan } = ENRICHMENT_MAP[code];
    await db
      .update(additives)
      .set({
        isVegetarian: sql`COALESCE(additives.is_vegetarian, ${isVegetarian})`,
        isVegan: sql`COALESCE(additives.is_vegan, ${isVegan})`,
      })
      .where(sql`additives.code = ${code}`);
    count++;
  }

  return count;
}
